-- NTC Cost Indices Seed — últimos 24 meses (Fev/2024 → Jan/2026)
-- Source: INCTL_0126.xlsx (R$/Ton por distância) + INCTF_0126.xlsx (Índice geral fracionado)
-- Generated by scripts/import-ntc-indices.cjs

-- INCTL: R$/Ton por faixa de distância (50, 400, 800, 2400, 6000 km)
ON CONFLICT (index_type, period, COALESCE(distance_km, 0), COALESCE(pickup_km, 0)) DO UPDATE SET index_value = EXCLUDED.index_value;

-- INCTF: Índice geral de custo do frete fracionado
ON CONFLICT (index_type, period, COALESCE(distance_km, 0), COALESCE(pickup_km, 0)) DO UPDATE SET index_value = EXCLUDED.index_value;

